  .strict()
  .superRefine((value, ctx) => {
    if (value.sessionId !== value.continuation.sessionId) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: "Implementor sessionId must match continuation.sessionId",
        path: ["continuation", "sessionId"],
      });
