  errors: CliError[];
  warnings: string[];
}

function blockedError(code: string, message: string, detail?: string): CliError {
  return {
    code,
    message,
    ...(detail ? { detail } : {}),
  };
}

function providerForHarness(harness: "codex" | "copilot" | "none"): ProviderName {
  if (harness === "none") {
    return "claude-code";
  }

  return harness;
}

function executionFailureError(input: {
  provider: ProviderName;
  stderr: string;
  errorCode?: string;
}): CliError {
  if (input.errorCode === "ENOENT") {
    return blockedError(
      "PROVIDER_UNAVAILABLE",
      `Provider executable is unavailable for ${input.provider}.`,
      input.stderr
    );
  }

  return blockedError(
    "PROVIDER_UNAVAILABLE",
    `Provider execution failed for ${input.provider}.`,
    input.stderr
  );
}

function parseVerifierReportContent(content: string): EpicVerifierResult[] | undefined {
  let parsed: unknown;
  try {
    parsed = JSON.parse(content);
  } catch {
    return undefined;
  }

  const directResult = epicVerifierResultSchema.safeParse(parsed);
  if (directResult.success) {
    return [directResult.data];
  }

  const directBatch = epicVerifierBatchResultSchema.safeParse(parsed);
  if (directBatch.success) {
    return directBatch.data.verifierResults;
  }

  const envelope = cliResultEnvelopeSchema(epicVerifierBatchResultSchema).safeParse(
    parsed
  );
  if (envelope.success && envelope.data.result) {
    return envelope.data.result.verifierResults;
  }

  return undefined;
}

async function loadVerifierReports(
  verifierReportPaths: string[]
): Promise<{ results?: EpicVerifierResult[]; errors?: CliError[] }> {
  const collected: EpicVerifierResult[] = [];

  for (const reportPath of verifierReportPaths) {
    const resolvedPath = resolve(reportPath);
    if (!(await pathExists(resolvedPath))) {
      return {
        errors: [
          blockedError(
            "INVALID_SPEC_PACK",
            `Verifier report was not found: ${resolvedPath}`
          ),
        ],
      };
    }

    if (!(await pathReadable(resolvedPath))) {
      return {
        errors: [
          blockedError(
            "INVALID_SPEC_PACK",
            `Verifier report is not readable: ${resolvedPath}`
          ),
        ],
      };
    }

    let content: string;
    try {
      content = await readTextFile(resolvedPath);
    } catch (error) {
      return {
        errors: [
          blockedError(
            "INVALID_SPEC_PACK",
            `Verifier report could not be read: ${resolvedPath}`,
            error instanceof Error ? error.message : String(error)
          ),
        ],
      };
    }

    const parsed = parseVerifierReportContent(content);
    if (!parsed) {
      return {
        errors: [
          blockedError(
            "INVALID_SPEC_PACK",
            `Verifier report was not valid JSON for the epic verifier contract: ${resolvedPath}`
          ),
        ],
      };
    }

    collected.push(...parsed);
  }

  return {
    results: collected,
  };
}

async function prepareSynthesisContext(input: {
  specPackRoot: string;
  verifierReportPaths: string[];
  configPath?: string;
}): Promise<PreparedSynthesisContext | { errors: CliError[] }> {
  const inspection = await inspectSpecPack(input.specPackRoot);
  if (inspection.status !== "ready") {
    return {
      errors: [
        blockedError(
          "INVALID_SPEC_PACK",
          "Spec-pack inspection must be ready before epic synthesis can start.",
          inspection.blockers.join("; ") || inspection.notes.join("; ")
        ),
      ],
    };
  }

  const reportResolution = await loadVerifierReports(input.verifierReportPaths);
  if (reportResolution.errors || !reportResolution.results) {
    return {
      errors:
        reportResolution.errors ??
        [
          blockedError(
            "INVALID_SPEC_PACK",
            "Epic synthesis requires at least one verifier report."
          ),
        ],
    };
  }

  const config = await loadRunConfig({
    specPackRoot: inspection.specPackRoot,
    configPath: input.configPath,
  });
  const gateResolution = await resolveVerificationGates({
    specPackRoot: inspection.specPackRoot,
  });
  if (gateResolution.status !== "ready" || !gateResolution.verificationGates) {
    return {
      errors: gateResolution.errors.length
        ? gateResolution.errors
        : [
            blockedError(
              "VERIFICATION_GATE_UNRESOLVED",
              "Verification gates must be resolved before epic synthesis can start."
            ),
          ],
    };
  }

  return {
    specPackRoot: inspection.specPackRoot,
    provider: providerForHarness(config.epic_synthesizer.secondary_harness),
    model: config.epic_synthesizer.model,
    reasoningEffort: config.epic_synthesizer.reasoning_effort,
    verifierReportPaths: input.verifierReportPaths.map((path) => resolve(path)),
    verifierResults: reportResolution.results,
    gateCommands: {
      story: gateResolution.verificationGates.storyGate,
      epic: gateResolution.verificationGates.epicGate,
    },
    paths: {
      epicPath: inspection.artifacts.epicPath,
      techDesignPath: inspection.artifacts.techDesignPath,
      techDesignCompanionPaths: inspection.artifacts.techDesignCompanionPaths,
      testPlanPath: inspection.artifacts.testPlanPath,
    },
  };
}

function buildSynthesisResult(payload: ProviderPayload): EpicSynthesisResult {
  return {
    resultId: randomUUID(),
    outcome: payload.outcome,
    confirmedIssues: payload.confirmedIssues,
    disputedOrUnconfirmedIssues: payload.disputedOrUnconfirmedIssues,
    readinessAssessment: payload.readinessAssessment,
    recommendedNextStep: payload.recommendedNextStep,
  };
}

export async function runEpicSynthesize(input: {
  specPackRoot: string;
  verifierReportPaths: string[];
  configPath?: string;
  env?: Record<string, string | undefined>;
}): Promise<EpicSynthesisWorkflowResult> {
  const context = await prepareSynthesisContext(input);
  if ("errors" in context) {
    return {
      outcome: "blocked",
      errors: context.errors,
      warnings: [],
    };
  }

  const prompt = await assemblePrompt({
    role: "epic_synthesizer",
    epicPath: context.paths.epicPath,
    techDesignPath: context.paths.techDesignPath,
    techDesignCompanionPaths: context.paths.techDesignCompanionPaths,
    testPlanPath: context.paths.testPlanPath,
    verifierReportPaths: context.verifierReportPaths,
    gateCommands: context.gateCommands,
  });
  const adapter = createProviderAdapter(context.provider, {
    env: input.env,
  });
  const execution = await adapter.execute({
    prompt: prompt.prompt,
    cwd: context.specPackRoot,
    model: context.model,
    reasoningEffort: context.reasoningEffort,
    timeoutMs: 30_000,
    resultSchema: providerPayloadSchema,
  });

  if (execution.exitCode !== 0) {
    return {
      outcome: "blocked",
      errors: [
        executionFailureError({
          provider: context.provider,
          stderr: execution.stderr,
          errorCode: execution.errorCode,
        }),
      ],
      warnings: [],
    };
  }

  if (execution.parseError || !execution.parsedResult) {
    return {
      outcome: "blocked",
      errors: [
        blockedError(
          "PROVIDER_OUTPUT_INVALID",
          `Provider output was invalid for ${context.provider}.`,
          execution.parseError
        ),
      ],
      warnings: [],
    };
  }

  const result = buildSynthesisResult(execution.parsedResult);
  return {
    outcome: result.outcome,
    result,
    errors: [],
    warnings: [],
  };
}

import { isAbsolute, relative, resolve } from "node:path";

import { loadRunConfig } from "./config-schema";
import { resolveGitRepoRoot } from "./git-repo";
import { createProviderAdapter, type ProviderName } from "./provider-adapters";
import type { CliError } from "./result-contracts";

interface QuickFixResultPayload {
  provider: ProviderName;
  model: string;
  rawProviderOutput: string;
}

export interface QuickFixWorkflowResult {
  outcome: "ready-for-verification" | "needs-more-routing" | "blocked";
  result?: QuickFixResultPayload;
  errors: CliError[];
  warnings: string[];
}

function blockedError(code: string, message: string, detail?: string): CliError {
  return {
    code,
    message,
    ...(detail ? { detail } : {}),
  };
}

function providerForHarness(harness: "codex" | "copilot" | "none"): ProviderName {
  if (harness === "none") {
    return "claude-code";
  }

  return harness;
}

function executionFailureError(input: {
  provider: ProviderName;
  stderr: string;
  errorCode?: string;
}): CliError {
  if (input.errorCode === "ENOENT") {
    return blockedError(
      "PROVIDER_UNAVAILABLE",
      `Provider executable is unavailable for ${input.provider}.`,
      input.stderr
    );
  }

  return blockedError(
    "PROVIDER_UNAVAILABLE",
    `Provider execution failed for ${input.provider}.`,
    input.stderr
  );
}

function isWithinRoot(root: string, target: string): boolean {
  const relativePath = relative(root, target);
  return (
    relativePath.length === 0 ||
    (!relativePath.startsWith("..") && !isAbsolute(relativePath))
  );
}

async function resolveWorkingDirectory(input: {
  specPackRoot: string;
  workingDirectory?: string;
}): Promise<{ workingDirectory?: string; errors?: CliError[] }> {
  const repoRoot = await resolveGitRepoRoot(input.specPackRoot);
  if (!repoRoot) {
    return {
      errors: [
        blockedError(
          "INVALID_SPEC_PACK",
          `Spec-pack root is not inside a git repo: ${resolve(input.specPackRoot)}`
        ),
      ],
    };
  }

  if (input.workingDirectory) {
    const workingDirectory = resolve(input.workingDirectory);
    if (!isWithinRoot(repoRoot, workingDirectory)) {
      return {
        errors: [
          blockedError(
            "INVALID_WORKING_DIRECTORY",
            "Quick-fix working directory must stay inside the resolved repo root.",
            `repoRoot=${repoRoot}; workingDirectory=${workingDirectory}`
          ),
        ],
      };
    }

    return {
      workingDirectory,
    };
  }

  return {
    workingDirectory: repoRoot,
  };
}

export async function runQuickFix(input: {
  specPackRoot: string;
  request: string;
  workingDirectory?: string;
  configPath?: string;
  env?: Record<string, string | undefined>;
}): Promise<QuickFixWorkflowResult> {
  const config = await loadRunConfig({
    specPackRoot: input.specPackRoot,
    configPath: input.configPath,
  });
  const provider = providerForHarness(config.quick_fixer.secondary_harness);
  const workingDirectoryResolution = await resolveWorkingDirectory({
    specPackRoot: input.specPackRoot,
    workingDirectory: input.workingDirectory,
  });
  if (workingDirectoryResolution.errors) {
    return {
      outcome: "blocked",
      errors: workingDirectoryResolution.errors,
      warnings: [],
    };
  }
  const workingDirectory = workingDirectoryResolution.workingDirectory;
  if (!workingDirectory) {
    return {
      outcome: "blocked",
      errors: [
        blockedError(
          "INVALID_WORKING_DIRECTORY",
          "Quick-fix working directory could not be resolved."
        ),
      ],
      warnings: [],
    };
  }
  const adapter = createProviderAdapter(provider, {
    env: input.env,
  });
  const execution = await adapter.execute({
    prompt: input.request,
    cwd: workingDirectory,
    model: config.quick_fixer.model,
    reasoningEffort: config.quick_fixer.reasoning_effort,
    timeoutMs: 30_000,
  });

  if (execution.exitCode !== 0) {
    return {
      outcome: "blocked",
      errors: [
        executionFailureError({
          provider,
          stderr: execution.stderr,
          errorCode: execution.errorCode,
        }),
      ],
      warnings: [],
    };
  }

  const rawProviderOutput = execution.stdout;
  if (rawProviderOutput.trim().length === 0) {
    return {
      outcome: "needs-more-routing",
      result: {
        provider,
        model: config.quick_fixer.model,
        rawProviderOutput,
      },
      errors: [],
      warnings: [
        "Quick-fix provider returned no stdout; inspect the run and choose the next routing step explicitly.",
      ],
    };
  }

  return {
    outcome: "ready-for-verification",
    result: {
      provider,
      model: config.quick_fixer.model,
      rawProviderOutput,
    },
    errors: [],
    warnings: [],
  };
}

import { resolve } from "node:path";

import { defineCommand } from "citty";
import { z } from "zod";

import { nextArtifactPath, writeJsonArtifact } from "../core/artifact-writer";
import { readTextFile } from "../core/fs-utils";
import { runQuickFix } from "../core/quick-fix";
import {
  cliResultEnvelopeSchema,
  createResultEnvelope,
  exitCodeForStatus,
  type CliArtifactRef,
  type CliError,
  type CliStatus,
} from "../core/result-contracts";

interface OutputEnvelope {
  command: string;
  version: 1;
  status: CliStatus;
  outcome: string;
  result?: unknown;
  errors: CliError[];
  warnings: string[];
  artifacts: CliArtifactRef[];
  startedAt: string;
  finishedAt: string;
}

const REQUEST_CONTENT_LIMIT_BYTES = 128 * 1024;

function renderHumanSummary(envelope: OutputEnvelope) {
  if (
    typeof envelope.result !== "object" ||
    envelope.result === null ||
    !("provider" in envelope.result)
  ) {
    return `quick-fix: ${envelope.outcome}`;
  }

  const result = envelope.result as {
    provider: string;
  };
  return [
    `quick-fix: ${envelope.outcome}`,
    `provider: ${result.provider}`,
  ].join("\n");
}

function emitOutput(params: {
  envelope: OutputEnvelope;
  json: boolean;
}) {
  if (params.json) {
    console.log(JSON.stringify(params.envelope));
    return;
  }

  console.log(renderHumanSummary(params.envelope));
}

async function resolveRequest(args: {
  "request-file"?: string;
  "request-text"?: string;
}): Promise<string> {
  const requestSources = [
    typeof args["request-file"] === "string" ? "file" : null,
    typeof args["request-text"] === "string" ? "text" : null,
  ].filter(Boolean);

  if (requestSources.length !== 1) {
    throw new Error("Provide exactly one of --request-file or --request-text.");
  }

  if (args["request-text"]) {
    const request = args["request-text"].trim();
    if (request.length === 0) {
      throw new Error("--request-text cannot be empty.");
    }
    if (Buffer.byteLength(request, "utf8") > REQUEST_CONTENT_LIMIT_BYTES) {
      throw new Error(
        `--request-text exceeds the 128 KiB limit (${REQUEST_CONTENT_LIMIT_BYTES} bytes).`
      );
    }
    return request;
  }

  const request = (await readTextFile(resolve(args["request-file"]!))).trim();
  if (request.length === 0) {
    throw new Error("--request-file cannot point to an empty task description.");
  }
  if (Buffer.byteLength(request, "utf8") > REQUEST_CONTENT_LIMIT_BYTES) {
    throw new Error(
      `--request-file exceeds the 128 KiB limit (${REQUEST_CONTENT_LIMIT_BYTES} bytes).`
    );
  }

  return request;
}

function hasFlag(rawArgs: string[], flag: string): boolean {
  return rawArgs.some((arg) => arg === flag || arg.startsWith(`${flag}=`));
}

function assertNoLegacyStoryAwareFlags(rawArgs: string[]) {
  if (
    hasFlag(rawArgs, "--story-id") ||
    hasFlag(rawArgs, "--story-title") ||
    hasFlag(rawArgs, "--story-path") ||
    hasFlag(rawArgs, "--scope-file")
  ) {
    throw new Error(
      "quick-fix does not accept story-aware flags such as --story-id, --story-title, --story-path, or --scope-file."
    );
  }
}

export default defineCommand({
  meta: {
    name: "quick-fix",
    description: "Run a bounded quick-fix with a free-form task description.",
  },
  args: {
    "spec-pack-root": {
      type: "string",
      description: "Absolute or relative path to the spec-pack root",
      required: true,
    },
    "request-file": {
      type: "string",
      description: "Path to a file containing the free-form quick-fix task",
    },
    "request-text": {
      type: "string",
      description: "Inline free-form quick-fix task description",
    },
    "working-directory": {
      type: "string",
      description: "Working directory for the quick-fix provider invocation",
    },
    config: {
      type: "string",
      description: "Explicit run-config file relative to the spec-pack root",
    },
    json: {
      type: "boolean",
      description: "Emit the structured JSON envelope on stdout",
    },
  },
  async run({ args, rawArgs }) {
    const startedAt = new Date().toISOString();
    const artifactPath = await nextArtifactPath(args["spec-pack-root"], "quick-fix");

    try {
      assertNoLegacyStoryAwareFlags(rawArgs);
      const request = await resolveRequest(args);
      const outcome = await runQuickFix({
        specPackRoot: args["spec-pack-root"],
        request,
        workingDirectory: args["working-directory"],
        configPath: args.config,
        env: process.env,
      });
      const envelope = cliResultEnvelopeSchema(z.unknown()).parse(
        createResultEnvelope({
          command: "quick-fix",
          outcome: outcome.outcome,
          result: outcome.result,
          errors: outcome.errors,
          warnings: outcome.warnings,
          artifacts: [
            {
              kind: "result-envelope",
              path: artifactPath,
            },
          ],
          startedAt,
          finishedAt: new Date().toISOString(),
        })
      );

      await writeJsonArtifact(artifactPath, envelope);
      emitOutput({
        envelope,
        json: Boolean(args.json),
      });
      process.exitCode = exitCodeForStatus(envelope.status, envelope.outcome);
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      const code =
        message.includes("--request-") ||
        message.includes("Provide exactly one") ||
        message.includes("does not accept story-aware flags")
          ? "INVALID_INVOCATION"
          : message.toLowerCase().includes("config")
            ? "INVALID_RUN_CONFIG"
            : "UNEXPECTED_ERROR";
      const outcome = code === "INVALID_RUN_CONFIG" ? "blocked" : "error";
      const envelope: OutputEnvelope = createResultEnvelope({
        command: "quick-fix",
        outcome,
        errors: [
          {
            code,
            message,
          },
        ],
        artifacts: [
          {
            kind: "result-envelope",
            path: artifactPath,
          },
        ],
        startedAt,
        finishedAt: new Date().toISOString(),
      });

      await writeJsonArtifact(artifactPath, envelope);
      emitOutput({
        envelope,
        json: Boolean(args.json),
      });
      process.exitCode = exitCodeForStatus(envelope.status, envelope.outcome);
    }
  },
});

